public class Main {
  static class IntegerNumber {
    protected String value;
    protected boolean hasSign;

    public IntegerNumber(boolean hasSign, String value) {
      this.hasSign = hasSign;
      this.value = value;
    }
    public String toString() {
      return (hasSign ? "-" : "+") + value;
    }
  }

  static class NaturalNumber extends IntegerNumber {
    public NaturalNumber(boolean hasSign, String value) {
      super(hasSign, value);
    }
    public String toString() {
      return "" + value;
    }
  }

  public static void main(String[] args) {
    IntegerNumber i = new IntegerNumber(true, "5");
    System.out.println(i);
    NaturalNumber n = new NaturalNumber(true, "7");
    System.out.println(n);
  }
}

