private List<TextDocument> documents = new ArrayList<>();

public void addDocument(TextDocument document){
  try {
    documents.add((TextDocument) document.clone());
  } catch (CloneNotSupportedException e) {
    e.printStackTrace();
  }
}

public TextDocument getPreviousDocument(){
  if(!history.isEmpty()){
    TextDocument document = documents.get(history.size()-1);
    documents.remove(document);
    return document;
  }
  throw new UnsupportedOperationException();
}

