public class Stack {
  private Deque<Integer> stack = new ArrayDeque<>();
  public void push(int value) {
    stack.push(value);
  }
  public int pop() {
    return stack.pop();
  }
  public boolean isEmpty() {
    return stack.isEmpty();
  }
}

@Test
public void testStack() {
  Stack s = new Stack();
  s.push(10);
  int x = s.pop();
  assertEquals(x, 10);
}

