public float getTicketPrice(int area, float basePrice, boolean groupReduction){
  float finalPrice = 0;
  switch(area){
    case 1:
      finalPrice = basePrice;
      break;
    case 2:
      finalPrice = basePrice * 1.2f;
      break;
    case 3:
      finalPrice = basePrice * 1.5f;
      break;
  }
  if(groupReduction)
    finalPrice = (float) (0.85 * finalPrice);
  return finalPrice;
}

